import type { Suggestion } from '../autocompletion-types.js';
/**
 * @internal
 */
export interface ListAutocompletionConfig {
    /** Regex that needs to match before in order to trigger the auto-completions */
    readonly matchBefore: RegExp;
    /** Auto-completions that are shown after the `matchBefore` RegExp was found. */
    autocompletionList: (() => Promise<Suggestion[]>) | Suggestion[];
    reopen?: boolean;
}
